package cmd

import (
	"os"

	"golang.org/x/term"

	"chezmoi.io/chezmoi/internal/chezmoi"
)

func (c *Config) exitInitTemplateFunc(code int) string {
	panic(chezmoi.ExitCodeError(code))
}

